#include <bits/stdc++.h>
using namespace std;;

int n, m, c[500005], d[500005], a[500005];

int lowbit(int x)
{
    return x & -x;
}

void add(int x, int k)
{
    for(; x <= n; x += lowbit(x))
        c[x] += k;
}

void upd(int l, int r, int k)
{
    add(l, k), add(r + 1, -k);
}

int getsum(int x)
{
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}

int main()
{
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for(int i = 1; i <= n; i++)
        d[i] = a[i] - a[i - 1];
    for(int i = 1; i <= n; i++)
        add(i, d[i]);
    for(int i = 1; i <= m; i++)
    {
        int op, x, y, k;
        cin >> op >> x;
        if(op == 1)
        {
            cin >> y >> k;
            upd(x, y, k);
        }
        else cout << getsum(x) << endl;
    }
}
